"""Bridge Protocol Buffer Definitions (Python module).

This module provides protobuf-compatible classes for gRPC communication.
In a production setup, this would be generated from a .proto file using protoc.
"""

from dataclasses import dataclass, field
from typing import Any


@dataclass
class Header:
    """Message header with metadata."""

    message_id: str = ""
    timestamp: int = 0
    client_id: str = ""


@dataclass
class Command:
    """Command message."""

    action: str = ""
    parameters: dict[str, Any] = field(default_factory=dict)


@dataclass
class CommandResponse:
    """Command response message."""

    success: bool = False
    data: str = ""
    error: str = ""


@dataclass
class Telemetry:
    """Telemetry data message."""

    topic: str = ""
    data: dict[str, Any] = field(default_factory=dict)


@dataclass
class Event:
    """Event message."""

    event_type: str = ""
    source: str = ""
    data: dict[str, Any] = field(default_factory=dict)


@dataclass
class Status:
    """Status message."""

    healthy: bool = False
    uptime_seconds: int = 0
    version: str = ""


