def add_BridgeServiceServicer_to_server(servicer, server):
    """Register BridgeService servicer to gRPC server.

    Args:
        servicer: The servicer implementation
        server: The gRPC server
    """
    # In real implementation, this would add the service to the server
    if hasattr(server, "add_servicer"):
        server.add_servicer(servicer)


# For compatibility with generated protobuf code
class BridgeServiceServicer:
    """Base class for BridgeService servicer."""

    async def SendCommand(self, request, context):
        """Handle SendCommand RPC."""
        raise NotImplementedError()

    async def HealthCheck(self, request, context):
        """Handle HealthCheck RPC."""
        raise NotImplementedError()

    async def SubscribeTelemetry(self, request, context):
        """Handle SubscribeTelemetry RPC."""
        raise NotImplementedError()

    async def SubscribeEvents(self, request, context):
        """Handle SubscribeEvents RPC."""
        raise NotImplementedError()

    async def StreamCommands(self, request_iterator, context):
        """Handle bidirectional StreamCommands RPC."""
        raise NotImplementedError()


